const headers = $input.first().json.headers || {};
const apiKey = headers['x-kb-api-key'] || '';
if (!$vars.KB_INGEST_API_KEY || apiKey !== $vars.KB_INGEST_API_KEY) {
  throw new Error('Unauthorized');
}

const body = $input.first().json.body || {};
const title = (body.title || 'Research ohne Titel').slice(0, 256);
const content = (body.content || '').slice(0, 50000);
const sourceUrl = (body.source_url || '').slice(0, 512);
const tags = (body.tags || []).map(t => String(t).replace(/[^\w-]/g, '').slice(0, 32)).slice(0, 10);
const docId = 'research_' + Date.now();

if (!content) throw new Error('content fehlt');

return [{ json: { docId, title, content, sourceUrl, tags } }];

