const validated = $('Validieren').first().json;
const entities = $('NLP Analyse').first().json.entities || [];
const summary = $('Zusammenfassung (Ollama)').first().json.message?.content || '';
const embedding = $('Embedding erstellen').first().json.embedding || [];

return [{
  json: {
    docId: validated.docId,
    title: validated.title,
    content: validated.content,
    summary: summary.slice(0, 1000),
    sourceUrl: validated.sourceUrl,
    tags: validated.tags,
    entities: entities,
    embedding: embedding
  }
}];

